INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd6474a98-d0de-478d-9fec-aecd19ef5f0b',
  '00000000-0000-0000-0000-000000000001',
  $escape$NestJS Input Validation — Schema Enforcement with class-validator and ValidationPipe$escape$,
  $escape$NestJS handles validation at the boundary using the global `ValidationPipe` paired with `class-validator` decorators on DTOs. Register it globally in `main.ts` with `whitelist: true` to strip undeclared properties, `forbidNonWhitelisted: true` to reject them outright, and `transform: true` to auto-coerce primitives (e.g., query string `'42'` → `number`).

Decorate DTO properties with `@IsString()`, `@IsEmail()`, `@IsInt()`, `@Min()`, `@IsEnum()`, etc. Nest validates the incoming payload against the DTO class shape before the handler runs — no manual parsing needed.

For sanitization, add `@Transform(({ value }) => value.trim())` from `class-transformer` directly on the field. This runs during the transform phase, keeping sanitization co-located with the schema.

Validation errors automatically return a `400 Bad Request` with a structured `errors` array per field. Customize the error shape by passing `exceptionFactory` to `ValidationPipe`. Never skip `whitelist` — it prevents mass-assignment attacks where clients inject fields like `isAdmin: true` that your DTO never declared.$escape$,
  $escape$// main.ts
app.useGlobalPipes(
  new ValidationPipe({
    whitelist: true,
    forbidNonWhitelisted: true,
    transform: true,
    exceptionFactory: (errors) => new BadRequestException({ message: 'Validation failed', errors }),
  }),
);

// create-user.dto.ts
export class CreateUserDto {
  @IsEmail()
  @Transform(({ value }) => value.toLowerCase().trim())
  email: string;

  @IsString()
  @MinLength(8)
  password: string;

  @IsEnum(Role)
  role: Role;
}$escape$,
