INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '051c4dd1-2118-453a-bac8-1123e9dd376d',
  '00000000-0000-0000-0000-000000000001',
  $escape$NestJS JWT Auth — Guards, Strategies, and Passport Integration$escape$,
  $escape$NestJS handles JWT authentication through Passport.js strategies wrapped in Guards. Define a `JwtStrategy` extending `PassportStrategy(Strategy)` — inject `ConfigService` to pull `JWT_SECRET` and implement `validate()` to return the user payload (this becomes `req.user`). Register it as a provider alongside `JwtModule.registerAsync()` in your `AuthModule`. Apply authentication by decorating routes or controllers with `@UseGuards(JwtAuthGuard)`, where `JwtAuthGuard` extends `AuthGuard('jwt')`. For global JWT enforcement, register the guard globally in `AppModule` using `APP_GUARD` provider token, then use a custom `@Public()` decorator to skip it on open endpoints — this inverts the default and is safer than opt-in guarding. Session handling in stateless JWT setups means no server-side state; store refresh tokens in `HttpOnly` cookies and rotate them on use. For role-based access, layer a second `RolesGuard` that reads `@Roles()` metadata via `Reflector` after JWT validation passes. Never decode JWTs manually — always let Passport verify the signature.$escape$,
  $escape$// jwt.strategy.ts
@Injectable()
export class JwtStrategy extends PassportStrategy(Strategy) {
  constructor(config: ConfigService) {
    super({
      jwtFromRequest: ExtractJwt.fromAuthHeaderAsBearerToken(),
      secretOrKey: config.get<string>('JWT_SECRET'),
    });
  }

  async validate(payload: { sub: string; email: string }) {
    return { userId: payload.sub, email: payload.email };
  }
}

// Mark public routes to bypass global JwtAuthGuard
export const Public = () => SetMetadata('isPublic', true);$escape$,
  $escape$typescript$escape$,
