INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '196b0b47-cbca-4c4c-996c-08e198acbcef',
  '00000000-0000-0000-0000-000000000001',
  $escape$NestJS Testing — Unit vs Integration, Mocking HTTP, and Test Database Strategy$escape$,
  $escape$NestJS's `Test.createTestingModule()` is your foundation for both unit and integration tests, but the strategy differs sharply. For unit tests, provide mock providers directly: `{ provide: UserService, useValue: mockUserService }`. Never spin up the full application — isolate the class under test. For integration tests, import the real module and use `app.init()` to wire the full DI graph, then hit controllers via `supertest`. Mock outbound HTTP by overriding `HttpModule` with a custom `HttpService` stub, or use `nock` to intercept at the Node layer — `nock('https://api.stripe.com').post('/charges').reply(200, fixture)`. For the test database, avoid in-memory SQLite when your real DB is PostgreSQL — schema parity breaks at edge cases. Instead, spin up Postgres via `@testcontainers/postgresql`, run TypeORM migrations before the suite, and truncate between tests using `dataSource.query('TRUNCATE ... CASCADE')`. Use `beforeAll` for the container and `beforeEach` for truncation. Never share mutable state across test files — NestJS module isolation makes this clean when modules are properly scoped.$escape$,
  $escape$// integration test with real DB via Testcontainers
beforeAll(async () => {
  pg = await new PostgreSqlContainer().start();
  const module = await Test.createTestingModule({
    imports: [AppModule],
  })
  .overrideProvider('DATA_SOURCE_URL')
  .useValue(pg.getConnectionUri())
  .compile();
  app = module.createNestApplication();
  await app.init();
  dataSource = module.get(DataSource);
  await dataSource.runMigrations();
});

afterEach(async () => {
  await dataSource.query('TRUNCATE users, orders CASCADE');
});

afterAll(async () => {
  await app.close();
  await pg.stop();
});$escape$,
