INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f86e1b94-b3c1-49dc-ba3b-504198d6140e',
  '00000000-0000-0000-0000-000000000001',
  $escape$NestJS Security Hardening — CORS, Helmet, Rate Limiting, and Injection Guards$escape$,
  $escape$NestJS ships with first-class support for the security primitives every production API needs. Enable Helmet via `app.use(helmet())` to set 15+ HTTP security headers (CSP, HSTS, X-Frame-Options) in one call. For CORS, pass a typed `CorsOptions` object to `app.enableCors()` — always whitelist specific origins rather than using `origin: '*'` in production. Rate limiting is handled by `@nestjs/throttler`: register `ThrottlerModule.forRoot()` globally, then apply `@Throttle()` per-route or bind `APP_GUARD` with `ThrottlerGuard` to protect every endpoint by default. For injection prevention, use class-validator with the `ValidationPipe` set to `whitelist: true` and `forbidNonWhitelisted: true` — this strips undeclared properties before they ever touch your handlers, neutralizing mass-assignment and unexpected-input attacks. Pair with `transform: true` so DTOs are hydrated as typed class instances, not raw plain objects. Together these four layers — headers, CORS policy, rate limits, and strict input validation — cover the most exploited attack surfaces without reaching for external middleware.$escape$,
  $escape$// main.ts
import helmet from 'helmet';
import { ThrottlerGuard, ThrottlerModule } from '@nestjs/throttler';
import { ValidationPipe } from '@nestjs/common';

async function bootstrap() {
  const app = await NestFactory.create(AppModule);

  app.use(helmet());

  app.enableCors({
    origin: ['https://app.yourdomain.com'],
    methods: ['GET', 'POST', 'PATCH', 'DELETE'],
    credentials: true,
  });

  app.useGlobalPipes(new ValidationPipe({
    whitelist: true,
    forbidNonWhitelisted: true,
    transform: true,
  }));

  await app.listen(3000);
}
bootstrap();$escape$,
