INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '190ed7a7-085f-4ded-a41e-2700b9e2652f',
  '00000000-0000-0000-0000-000000000001',
  $escape$NestJS Serialization — DTOs, camelCase/snake_case, and Null Safety with class-transformer$escape$,
  $escape$NestJS leans on `class-transformer` to control exactly what leaves your API. Slap `@Exclude()` on your entity class and `@Expose()` on only the fields you want — then enable the `ClassSerializerInterceptor` globally so every controller response is automatically transformed. For camelCase → snake_case, add `@Transform(({ key }) => snakeCase(key))` per field, or configure `plainToInstance` with a custom `strategy`. A cleaner approach: define a dedicated response DTO and map to it explicitly, keeping entity internals out of the wire format entirely. For null handling, `@Expose({ toPlainOnly: true })` combined with `@Transform(({ value }) => value ?? undefined)` strips null fields from the JSON payload — useful when your frontend treats missing keys and nulls differently. Avoid relying on the raw entity as a response type; even with `@Exclude()`, refactors silently break your API contract. Always pair `plainToInstance(ResponseDto, data, { excludeExtraneousValues: true })` with `@Expose()` decorators so only declared fields survive serialization.$escape$,
  $escape$// main.ts
app.useGlobalInterceptors(new ClassSerializerInterceptor(app.get(Reflector)));

// user-response.dto.ts
import { Expose, Transform } from 'class-transformer';

export class UserResponseDto {
  @Expose()
  id: string;

  @Expose()
  @Transform(({ value }) => value ?? undefined)
  avatarUrl: string | null;

  @Expose({ name: 'created_at' })
  createdAt: Date;
}

// users.service.ts
return plainToInstance(UserResponseDto, user, { excludeExtraneousValues: true });$escape$,
  $escape$typescript$escape$,
