INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a3aa9ceb-6a6b-42aa-b382-aadbdc539220',
  '00000000-0000-0000-0000-000000000001',
  $escape$NestJS Monitoring — Health Checks, Prometheus Metrics, and Distributed Tracing$escape$,
  $escape$NestJS ships `@nestjs/terminus` for structured health checks. Decorate a controller method with `@HealthCheck()` and pass an array of indicator functions to `HealthCheckService.check()`. Built-in indicators cover TypeORM, Prisma, Redis, HTTP, and Mongoose — each returns a `HealthIndicatorResult` that terminus aggregates into a single `{ status, info, error, details }` response your load balancer can probe.

For metrics, add `@willsoto/nestjs-prometheus`. It auto-registers a `/metrics` endpoint, exposes default Node.js process metrics, and lets you inject custom counters or histograms via `@InjectMetric('name')` directly into services.

Distributed tracing requires bootstrapping `@opentelemetry/sdk-node` *before* `NestFactory.create()` — the SDK must patch HTTP and Express before the app wires up. Install `@opentelemetry/instrumentation-nestjs-core` to automatically trace guards, interceptors, pipes, and exception filters as named spans. Context propagates through `AsyncLocalStorage`, so child spans inside services attach to the active trace without manual `context.with()` calls. Combine with a Jaeger or OTLP exporter and you get end-to-end visibility from HTTP ingress to DB query.$escape$,
  $escape$import { Controller, Get } from '@nestjs/common';
import {
  HealthCheck,
  HealthCheckService,
  HttpHealthIndicator,
  TypeOrmHealthIndicator,
} from '@nestjs/terminus';

@Controller('health')
export class HealthController {
  constructor(
    private health: HealthCheckService,
    private http: HttpHealthIndicator,
    private db: TypeOrmHealthIndicator,
  ) {}

  @Get()
  @HealthCheck()
  check() {
    return this.health.check([
      () => this.db.pingCheck('database'),
      () => this.http.pingCheck('upstream', 'https://api.example.com/ping'),
    ]);
  }
}$escape$,
